<?php namespace App\Repositories\Fee;use App\Repositories\BaseRepository;use App\Models\Fee\FeeDiscount;use Illuminate\Database\Eloquent\Collection;class FeeDiscountRepository extends BaseRepository{    public function __construct(FeeDiscount $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByCode(string $code): ?FeeDiscount    {        return $this->query()->where('code', $code)->first();    }    public function findByStudent(int $studentId): Collection    {        return $this->findByField('student_id', $studentId);    }    public function findByFeeStructure(int $feeStructureId): Collection    {        return $this->findByField('fee_structure_id', $feeStructureId);    }    public function getActiveDiscounts(): Collection    {        return $this->query()->where('is_active', true)->where(function ($q) {                $q->whereNull('valid_until')->orWhere('valid_until', '>=', now());            })->get();    }    public function getByDiscountType(string $type): Collection    {        return $this->findByField('discount_type', $type);    }    public function searchDiscounts(string $keyword): Collection    {        return $this->query()->where('code', 'like', "%{$keyword}%")->orWhere('name', 'like', "%{$keyword}%")->orWhere('description', 'like', "%{$keyword}%")->get();    }}